import pyotp
import qrcode

# Generate TOTP secret for a user
def generate_totp_secret(username):
    totp = pyotp.TOTP(pyotp.random_base32_string(length=20))
    return totp.secret

# Create QR code for an authenticator app
def create_qr_code(secret):
    qr = qrcode.QRCode()
    qr.add_data(secret)
    qr.make(fit=True)
    return qr.make_image()

# Validate TOTP code
def validate_totp_code(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code)